external_knowledge:
- "gardeners with blossoming accounts" refers to clients whose accounts are active; 
- "seeds of the most ambitious planting intention" metaphorically refers to the highest initial investment in a portfolio;
- `MAX(portfolios.initial_investment)` indicates the highest initial investment amount.

sql:
SELECT instrument_type_name, description
FROM instrument_types
WHERE instrument_type_id = 0;

SELECT industry_name, description
FROM instrument_industry
WHERE industry_name = 'Banking';

SELECT transaction_id, account_id, instrument, type, quantity, price
FROM trading_transactions
WHERE price > (SELECT AVG(price) FROM market_data WHERE instrument_id = 1);

SELECT risk_id
FROM risk_management
WHERE risk_id > 5;
